VALUES
  ('social-worker-moex-05800', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於社會工作的保密責任，下列何者正確？①違反保密不僅損害公平原則，也是洩漏訊息  ②保密並非', '["即使案主分享的秘密違法，社會工作人員都要保密", "社會工作人員因為法律上的需要而進行通報時就是洩密  ⑤社會工作人員紀錄不超過機構所需要的資 料就是保密", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05801', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於「社會團體工作」的敘述，何者錯誤？', '["協助社會大眾組織人民團體，故稱為「社會團體」", "透過團體互動與方案活動達成個人成長與社會目標的完成", "個人行為的改變是目的之一", "具有復健（rehabilitation）的功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05802', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Yalom在1983年以及Bloch和Crouch在1985年分別提出了團體工作對於團體成員個人可以產生的治療 性因素，請問下列對於團體中治療性因素的敘述，何者正確？', '["「植入希望」因素指的是團體可以提供成員觀察其他成員行為來學習新行為的機會", "「自我表露」因素是成員能夠分享自己的經驗，以及對團體和其他成員的感覺", "「接納」因素是指團體中的成員可由其他團體成員的改變，連結至自身經驗，使他們能樂觀性看待自 己可能的改變", "「替代學習」因素指的是團體可以使成員感覺不被排斥且受重視，並產生新的自我價值觀因而願意改變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05803', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據Toseland和Rivas對於處遇性團體（treatment groups）類型目的的看法，下列那些團體是屬於處遇性', '["器官移植小組", "社區大樓的管理委員會", "少年性教育團體", "戒酒匿名團體  ⑤單親家長 的支持性團體  ⑥基金會裡的董事會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05804', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於團體工作契約的敘述何者錯誤？', '["內容應包含出席會期與收費與否", "內容應包含團體整體與機構間的約定", "團體初期應訂定互惠契約與互助契約", "團體結束期訂定獨立契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05805', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體形成期，工作者的地位是軸承的位置（pivotal location），是指：', '["工作者協助成員界定每一個位置的本質", "工作者可透過角色安排來增強弱者的權力", "工作者協助成員表達概念，擴充其原有概念", "工作者視團體需要站在核心或邊陲地位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05806', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會團體工作中，關於互助契約與互賴契約的敘述，下列何者正確？', '["互賴契約是互助契約的一種", "互助契約隱含著依賴與獨立", "互助契約在團體衝突階段開始建立", "互賴契約中，工作者與成員都相互依賴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05807', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於社會團體工作歷程的敘述，何者錯誤？', '["團體領導者未將團體組成的訊息公諸於世，稱為團體前的私下期", "成員開始與他人互動、建立人際連結、扮演團體角色，稱為團體聚集期", "通常一開始團體總是充斥不滿、緊張、多話的", "並非所有團體都會經歷團體衝突期"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05808', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體帶領者可以透過一些測量資料，來了解成員在團體中的行為改變。在一個親職教育團體中，這些資', '["該團體成員的政黨傾向表態", "該團體成員的自我評量", "該團體成員子女的回饋", "該團體工作者的評量  ⑤該團體的觀察員評量  ⑥該團體成員的收入改善情形"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05809', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於團體工作規範的敘述，下列何者錯誤？', '["規範可以分為正式規範與非正式規範兩種", "團體規範具備幫助團體形成團體文化的功能", "規範能用來維繫團體成員的認同與凝聚力", "團體規範是對團體中特定成員功能的期待"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
